import boto3
import json

sqs = boto3.resource('sqs')

def send_message(queue_url, message_body):
    try:
        sqs.send_message(
            QueueUrl=queue_url,
            MessageBody=json.dumps(message_body)
        )
        print(f"Message sent successfully: {message_body}")
    except Exception as e:
        print(f"Failed to send message: {e}")

def publish_user_data(queue_url, user_id, email, phone_number, address):
    message_body = {
        'user_id': user_id,
        'email': email,
        'phone_number': phone_number,
        'address': address
    }
    send_message(queue_url, message_body)

# Example usage:
queue_url = "https://sqs.us-east-1.amazonaws.com/123456789012/myqueue"
user_id = 12345
email = "john.doe@example.com"
phone_number = "+1234567890"
address = "123 Main St, Anytown USA"

publish_user_data(queue_url, user_id, email, phone_number, address)